app = Flask(__name__)
app.secret_key = 'dev-secret-key-change-in-production'

login_manager = LoginManager()
login_manager.init_app(app)

# Simulated user store for MVP
users_db = {}


class User(UserMixin):
    def __init__(self, id, username, email, account_type='free', credits=0,
                 referral_code=None, verified_status=False):
        self.id = id
        self.username = username
        self.email = email
        self.account_type = account_type
        self.credits = credits
        self.referral_code = referral_code
        self.verified_status = verified_status

    def to_dict(self):
        return {
            'id': self.id,
            'username': self.username,
            'email': self.email,
            'account_type': self.account_type,
            'credits': self.credits,
            'referral_code': self.referral_code,
            'verified_status': self.verified_status,
        }


@login_manager.user_loader
def load_user(user_id):
    return users_db.get(user_id)


# Fields that users are allowed to modify on their own profile
# account_type, credits, and verified_status are EXCLUDED because:
# - account_type: should only change via payment processing (upcoming feature)
# - credits: should only change via purchase/usage logic, not direct user input
# - verified_status: should only change via verification workflow (e.g., email confirmation)
USER_MODIFIABLE_FIELDS = {'email', 'username', 'referral_code'}

# Fields that require privileged access (admin endpoints, payment callbacks, etc.)
PRIVILEGED_FIELDS = {'account_type', 'credits', 'verified_status'}


def validate_email(email):
    """Basic email validation for MVP."""
    if not isinstance(email, str):
        return False
    if len(email) > 254:
        return False
    parts = email.split('@')
    if len(parts) != 2:
        return False
    local, domain = parts
    if not local or not domain or '.' not in domain:
        return False
    return True


def validate_username(username):
    """Basic username validation for MVP."""
    if not isinstance(username, str):
        return False
    if len(username) < 3 or len(username) > 30:
        return False
    if not username.isalnum() and not all(c.isalnum() or c in ('_', '-') for c in username):
        return False
    return True


def validate_referral_code(referral_code):
    """Basic referral code validation for MVP."""
    if not isinstance(referral_code, str):
        return False
    if len(referral_code) > 20:
        return False
    if not referral_code.isalnum():
        return False
    return True


@app.route('/api/profile', methods=['PUT', 'PATCH'])
@login_required
def update_profile():
    """
    Update the current user's profile.

    Users can modify: email, username, referral_code.

    Privileged fields (account_type, credits, verified_status) cannot be
    modified through this endpoint to prevent broken access control.
    These will be managed through dedicated admin/payment endpoints.
    """
    data = request.get_json()

    if not data or not isinstance(data, dict):
        return jsonify({'error': 'Request body must be a JSON object'}), 400

    # Check for attempts to modify privileged fields
    attempted_privileged = set(data.keys()) & PRIVILEGED_FIELDS
    if attempted_privileged:
        return jsonify({
            'error': 'You do not have permission to modify the following fields',
            'fields': sorted(attempted_privileged),
            'message': 'Fields like account_type, credits, and verified_status '
                       'cannot be changed directly. Use the appropriate workflows '
                       '(e.g., payment processing, email verification).'
        }), 403

    # Filter to only recognized modifiable fields; ignore unknown fields
    updates = {k: v for k, v in data.items() if k in USER_MODIFIABLE_FIELDS}

    if not updates:
        return jsonify({
            'error': 'No valid fields to update',
            'modifiable_fields': sorted(USER_MODIFIABLE_FIELDS)
        }), 400

    # Validate each field
    errors = {}

    if 'email' in updates:
        if not validate_email(updates['email']):
            errors['email'] = 'Invalid email format'
        else:
            # Check uniqueness (MVP: simple check against in-memory store)
            for uid, user in users_db.items():
                if uid != current_user.id and user.email == updates['email']:
                    errors['email'] = 'Email already in use'
                    break

    if 'username' in updates:
        if not validate_username(updates['username']):
            errors['username'] = ('Invalid username. Must be 3-30 characters, '
                                  'alphanumeric with underscores and hyphens allowed.')
        else:
            # Check uniqueness
            for uid, user in users_db.items():
                if uid != current_user.id and user.username == updates['username']:
                    errors['username'] = 'Username already in use'
                    break

    if 'referral_code' in updates:
        if not validate_referral_code(updates['referral_code']):
            errors['referral_code'] = ('Invalid referral code. Must be alphanumeric, '
                                       'max 20 characters.')

    if errors:
        return jsonify({'error': 'Validation failed', 'details': errors}), 422

    # Apply updates to the current user
    for field, value in updates.items():
        setattr(current_user, field, value)

    # In a real app, persist to database here
    users_db[current_user.id] = current_user

    return jsonify({
        'message': 'Profile updated successfully',
        'updated_fields': sorted(updates.keys()),
        'profile': current_user.to_dict()
    }), 200


@app.route('/api/profile', methods=['GET'])
@login_required
def get_profile():
    """Get the current user's profile."""
    return jsonify({'profile': current_user.to_dict()}), 200


